var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"이건 약속이 틀리잖아요!","JPN":"約束が違うじゃないですか！","ENG":"This isn't what you promised me!","TWN":"這跟說好的不一樣吧！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"분명 최고가 되게 해주겠다며! 그래서 사인한 건데!","JPN":"トップにしてくれるって言いましたよね！　だからサインしたのに！","ENG":"You said you'd make me the greatest! That's why I signed the contract!","TWN":"妳不是說要讓我成為頂尖的偶像嗎！所以我才簽名的耶！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그런데 이미 리더가 있다는 게 말이나 되냐고!","JPN":"なのにもうリーダーが決まってるなんて、\\nこんなのあり得ないでしょう！？","ENG":"And now you're telling me there's already a leader?!","TWN":"為什麼隊長已經有人當了，太沒道理了！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"심지어! 이런 의욕도 없게 생긴 애가!","JPN":"しかも！　よりによって、こんなやる気のなさそうな子だなんて！","ENG":"Worse yet... She doesn't even seem to give a hoot about being leader!","TWN":"而且！還是這種一點幹勁都沒有的傢伙！"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"후훗, 아이돌 그룹은 혼자선 최고가 될 수 없어.","JPN":"ふふっ、アイドルグループはね、\\n一人の力じゃトップには立てないの。","ENG":"Hah hah, you can't become the greatest star by yourself when you're in a girl group.","TWN":"呵呵，偶像團體光靠一個人，是無法成為頂尖的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"노력해서 성공했을 땐, 너희 모두가 최고가 되는 거야.","JPN":"みんなで努力して成功を収めたときに、\\nあなたたち全員がトップアイドルになるのよ。","ENG":"You'll only become the best when you work together as a team.","TWN":"只有努力獲得成功的時候，妳的一切才會達到頂尖。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"그런 말장난 인정 못해! 리더가 주인공인 게 당연하잖아!","JPN":"そんな詭弁、認めないわ！　本当のトップは\\n主役であるリーダーだけに決まってるじゃない！","ENG":"That's just a lame excuse! Obviously the leader is the main character!","TWN":"我才不會承認那種歪理！隊長當然是主角啊！"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"흐음, 노력한다면 안 될 것도 없지 않겠니?","JPN":"そう思うなら、やはり\\n努力するしかないんじゃないかしら。","ENG":"Hmm, you never know if you tried hard enough...","TWN":"哦，妳願意努力的話，也不是不行喔？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"네가 리더에 어울릴 만큼 잘 적응한다면, 그땐 네가 원하지 않아도 내가 널 리더로 만들어 줄 거야.","JPN":"あなたがリーダーとして相応しい成長を遂げたときは、\\nあなたが望まなくたってリーダーにしてあげるわ。","ENG":"If you get acclimated enough to become a leader, I'll make you the leader then. Whether you like it or not.","TWN":"如果妳變得更適合當隊長，即使妳不願意，我也會讓妳當隊長的。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHOIENA_HB_NULL_NULL","text":{"KOREA":"그러니 그렇게 계속 칭얼거리기 보단, 앞으로 서로 잘 지내는 법부터 익히는 게 좋겠지?","JPN":"だから文句ばかり言ってないで、\\nみんなと仲良くした方が賢明だと思うわよ？","ENG":"So you'd better learn to get along with everyone instead of whining about it. Okay?","TWN":"與其在這邊大吵大鬧，先學學要怎麼和隊友們好好相處如何？"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"CHOIENA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"크으으......","JPN":"くっ……","ENG":"Argh...","TWN":"唔唔……"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"쳇...... 맞는 말만 하니까, 할말이 없네.","JPN":"フン……何よ、正論ばかり言ってくれちゃって。\\nぐうの音も出ないじゃないの。","ENG":"Hmpf... It sucks that she's right about everything. Now I can't complain.","TWN":"嘖……妳說得對，我無話可說。"},"stage":{"bg":"OFFICE","slots":{"L":null,"C":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"너 말이야. 왜 아이돌이 되려고 하는 거야?","JPN":"あなた、どうしてアイドルになりたいの？","ENG":"Hey, you. Why are you trying to become a star?","TWN":"妳啊，為什麼會想當偶像？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"카운터가 돈을 버는 방법이라면 말이지. 굳이 이런 것 말고도 아주 많다고.","JPN":"カウンターだったら、他に\\nお金を儲ける方法がいくらでもあるじゃない。","ENG":"I mean, if you want to make money as a Counter, there's lots of other ways to do it.","TWN":"制裁者要賺錢，就算不刻意來當偶像，還有恨多方法吧。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"GAEUN_HB_NULL_NULL","text":{"KOREA":"찾고 싶은 사람이 있어.","JPN":"……人探し。","ENG":"There's someone I want to find.","TWN":"我有個想找的人。"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"Huh?","TWN":"什麼？"},"stage":{"bg":"OFFICE","slots":{"L":{"char_id":"GAEUN_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};